var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"계속 일어나고 있어요.","JPN":"何度倒してもまた立ち上がってきます。","ENG":"They keep getting back up.","TWN":"他們還在不斷爬起來。"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"자기들끼리 뜯어먹으면서 상처를 재생하는 것 같은데요?","JPN":"どうやら互いの肉を食べて傷を癒やしているようですね。","ENG":"It looks like they're regenerating by tearing into each other?","TWN":"他們好像是一邊互相啃食，一邊再生傷口。"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MINHA_G1_STUDENT_NULL","text":{"KOREA":"으응… 아마 그런 원리일걸?","JPN":"う～ん……多分そんな感じの原理なんじゃない？","ENG":"Yeah... That's probably how it works.","TWN":"嗯……大概就是那樣的機制吧？"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"MINHA_G1_STUDENT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MINHA_G1_STUDENT_NULL","text":{"KOREA":"언니는 비위도 좋구나? 난 저거 처음 봤을 때 토했는데.","JPN":"姉さんって肝がすわってるんだね。私はあれ初めて見たときゲロ吐いたのに。","ENG":"You've got a strong stomach. I threw up the first time I saw that.","TWN":"姐姐你膽子真大耶？我第一次看到的時候都吐了。"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"MINHA_G1_STUDENT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CULTIST_NPC_NULL_QM","text":{"KOREA":"부부질질없는는 저항이다.","JPN":"ムム無駄ナナ抵抗だ。","ENG":"Th-th-this is a f-futile resistance.","TWN":"這是徒勞無功的反抗。"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"CULTIST_NPC_NULL_QM","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CULTIST_NPC_NULL_QM","text":{"KOREA":"암군은 결국 작은 왕을 거두고, 그분께서는 언약궤에 신의 열매를 담을 것이니.","JPN":"最後には暗君は小さき王を捕らえ、あのお方は契約の箱に神の実を収めるであろう。","ENG":"The Ignorant Monarch will ultimately claim the little queen, and she shall place the Godfruit within the Ark.","TWN":"暗軍終將回收小王。而那一位，會將神之果實置於約櫃。"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"CULTIST_NPC_NULL_QM","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MINHA_G1_STUDENT_NULL","text":{"KOREA":"너네, 그거 도망치기 직전에 하는 멘트지?","JPN":"はいはい、逃げる前の捨て台詞ね。","ENG":"That's the kind of thing you say right before running away, isn't it?","TWN":"那句話是你們逃跑前的固定台詞吧？"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"MINHA_G1_STUDENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CULTIST_NPC_NULL_QM","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"CULTIST_NPC_NULL_QM","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"사라졌어. 감쪽같이.","JPN":"消えた。跡形もなく……","ENG":"They're gone. Completely vanished.","TWN":"消失了。無影無蹤。"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"쫓아가야 할까요?!","JPN":"追ったほうがいいでしょうか！？","ENG":"Should we go after them?!","TWN":"要追上去嗎？！"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MINHA_G1_STUDENT_NULL","text":{"KOREA":"도망치면서 함정을 파뒀을 거야. 저것들, 말은 어눌하게 해도 생각 이상으로 교활하거든.","JPN":"逃げながら罠を仕掛けていったはずだよ。あいつら、話し方は変でも想像以上に狡猾だから。","ENG":"They probably set traps while retreating. They may sound incoherent, but they're more cunning than they look.","TWN":"他們一定一邊逃一邊設下陷阱。那些傢伙說話雖然結巴，想法卻意外狡猾。"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"MINHA_G1_STUDENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MINHA_G1_STUDENT_NULL","text":{"KOREA":"의욕이 앞서는 것도 좋지만 그 상처부터 돌보지?","JPN":"あのさ、やる気があるのはいいけど、まず傷の手当をしたら？","ENG":"Enthusiasm's good, but shouldn't you tend to that wound first?","TWN":"有幹勁是好事，不過還是先處理你的傷口吧？"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"MINHA_G1_STUDENT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"아… 그렇네요. 모모가 보면 놀라겠다.","JPN":"あ……そうですね。モモが見たらびっくりしてしまいますよね。","ENG":"Ah... you're right. Momo would panic if she saw this.","TWN":"啊……也是。莫莫看到的話，一定會嚇一跳。"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MINHA_G1_STUDENT_NULL","text":{"KOREA":"…치료도 능숙하네.","JPN":"……治療の腕もよか。","ENG":"...She's skilled at treatment, too.","TWN":"……治療也很熟練呢。"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"MINHA_G1_STUDENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"MINHA_G1_STUDENT_NULL","text":{"KOREA":"바텐더는 위장신분일 뿐이란 건가.","JPN":"バーテンダーっちいうんは偽装用に過ぎんゆうことやろか。","ENG":"So the bartender act really was just a cover.","TWN":"所以酒保只是偽裝身分嗎？"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"MINHA_G1_STUDENT_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L29_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"손님은 이전에도 저런 사람들을 상대해본 거죠?","JPN":"お客様は前にもああいった人たちと戦ったことがあるんですね？","ENG":"You've dealt with people like them before, haven't you?","TWN":"你以前也對付過那些人嗎？"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MINHA_G1_STUDENT_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L30_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"저 사람들의 정체도 알고 있는 건가요?","JPN":"ならあの人たちの正体もご存じなんですか？","ENG":"Do you know who they really are?","TWN":"也知道他們的真實身分嗎？"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MINHA_G1_STUDENT_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L31_1","type":"dialog","speaker":"MINHA_G1_STUDENT_NULL","text":{"KOREA":"…너무 알려고 하지 마. 알면 다쳐.","JPN":"……あまり詮索しないほうがいいよ。痛い目に遭うから。","ENG":"...Don't dig too deep. Knowing too much gets you hurt.","TWN":"……別知道太多，知道了會受傷的。"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"MINHA_G1_STUDENT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"아 참, 난 민하야. 은인의 이름이니 딴 건 몰라도 이것만은 잘 새겨두라고.","JPN":"あ、紹介が遅れたけど私はミウ。恩人の名前だからこれだけは忘れないでね。","ENG":"Oh, right. I'm Minha. Remember that name, at least. It belongs to your life-saver.","TWN":"對了，我叫敏荷。其他忘了都沒關係，救命恩人的名字一定要記住。"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"그럼 난 이만… 흐앗?!","JPN":"じゃあ私はこれで……うあっ！？","ENG":"Well then, I'll be– Huh?!","TWN":"那我就先……咦？！"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"뭔데? 갑자기 백허그?","JPN":"何なの！？　急に後ろから抱きついて？","ENG":"What's with the back hug?","TWN":"怎麼了？突然從後面抱上來？"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"고마워요. 우릴 도와줘서.","JPN":"ありがとうございます。私たちを助けてくれて。","ENG":"Thank you. For helping us.","TWN":"謝謝你。謝謝你幫了我們。"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"이 은혜는 잊지 않을게요.","JPN":"この恩は忘れません。","ENG":"I won't forget this kindness.","TWN":"這份恩情，我不會忘記。"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L38_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"},"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L39_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"뭐야, 이 언니?","JPN":"何や、この姉さん？","ENG":"What's with her?","TWN":"什麼啊，這位姐姐？"},"stage":{"bg":"GREMORY_BAR","slots":{"L":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L40_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"뒤에서 다가오는데도 기척을 전혀 못 느꼈어.","JPN":"後ろから近づいてきよったとに、ちっとも気配がせんやった。","ENG":"She came up behind me and I didn't sense her at all.","TWN":"明明從背後靠近，我卻完全沒察覺到氣息。"},"stage":{"bg":"GREMORY_BAR","slots":{"L":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L42_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"그… 감사하는 건 좋은데, 스킨십은 허락은 받고 하지?","JPN":"その……感謝してくれるのはいいんだけど、スキンシップは先に言ってからにしてくれる？","ENG":"I mean... gratitude's nice and all, but shouldn't you ask before getting handsy?","TWN":"那個……表達感謝是好事，不過要先徵求同意才能肢體接觸吧？"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L45_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"앗, 죄송해요.","JPN":"あっ、すみません。","ENG":"Ah, I'm sorry.","TWN":"啊，對不起！"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"나중에라도 사례하고 싶은데, 전화번호라도…","JPN":"後日にお礼をさせていただきたいのですが、電話番号でも……","ENG":"I'd like to repay you somehow later. Maybe your phone number–","TWN":"我之後想正式跟你道謝，至少留下電話號碼……"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};